import json


def parse_bounded_json_object(data: bytes, max_bytes: int = 16384) -> dict[str, object]:
    if not isinstance(data, bytes):
        raise TypeError("data must be bytes")
    if isinstance(max_bytes, bool) or not isinstance(max_bytes, int) or max_bytes < 1:
        raise ValueError("max_bytes must be a positive integer")
    if len(data) > max_bytes:
        raise ValueError("request body is too large")

    try:
        text = data.decode("utf-8", errors="strict")
    except UnicodeDecodeError as exc:
        raise ValueError("request body is not valid UTF-8") from exc

    def reject_constant(value: str) -> object:
        raise ValueError(f"non-finite JSON number is not allowed: {value}")

    try:
        value = json.loads(text, parse_constant=reject_constant)
    except json.JSONDecodeError as exc:
        raise ValueError("request body is not valid JSON") from exc

    if not isinstance(value, dict):
        raise ValueError("request body must be a JSON object")
    return value

from urllib.parse import urlsplit


def require_local_redirect(value: str) -> str:
    if not isinstance(value, str):
        raise TypeError("redirect target must be a string")
    if value != value.strip() or not value:
        raise ValueError("redirect target must not contain surrounding whitespace")
    if any(ord(char) < 32 or ord(char) == 127 for char in value):
        raise ValueError("redirect target contains a control character")
    if "\\" in value or not value.startswith("/") or value.startswith("//"):
        raise ValueError("redirect target must be a local absolute path")

    parts = urlsplit(value)
    if parts.scheme or parts.netloc or not parts.path.startswith("/"):
        raise ValueError("redirect target must not contain an origin")
    return value

def redact_log_fields(
    record: dict[str, object], sensitive_names: set[str]
) -> dict[str, object]:
    if not isinstance(record, dict):
        raise TypeError("record must be a dict")
    if not isinstance(sensitive_names, set):
        raise TypeError("sensitive_names must be a set")

    normalized: set[str] = set()
    for name in sensitive_names:
        if not isinstance(name, str) or not name.strip():
            raise ValueError("sensitive names must be non-blank strings")
        normalized.add(name.casefold())

    result: dict[str, object] = {}
    for key, value in record.items():
        if not isinstance(key, str):
            raise TypeError("record keys must be strings")
        result[key] = "[REDACTED]" if key.casefold() in normalized else value
    return result

def validate_upload_metadata(
    name: str,
    content_type: str,
    size: int,
    allowed_types: set[str],
    max_bytes: int,
) -> tuple[str, str, int]:
    if not isinstance(name, str) or name != name.strip() or not name:
        raise ValueError("name must be a non-blank trimmed string")
    if len(name) > 128 or name in {".", ".."}:
        raise ValueError("invalid upload name")
    if "/" in name or "\\" in name or any(ord(c) < 32 or ord(c) == 127 for c in name):
        raise ValueError("upload name contains a forbidden character")

    if not isinstance(content_type, str) or content_type != content_type.strip().lower():
        raise ValueError("content_type must be canonical lowercase text")
    if not isinstance(allowed_types, set) or any(
        not isinstance(item, str) or item != item.strip().lower() or not item
        for item in allowed_types
    ):
        raise ValueError("allowed_types must contain canonical lowercase strings")
    if content_type not in allowed_types:
        raise ValueError("content type is not allowed")

    if isinstance(max_bytes, bool) or not isinstance(max_bytes, int) or max_bytes < 0:
        raise ValueError("max_bytes must be a non-negative integer")
    if isinstance(size, bool) or not isinstance(size, int) or not 0 <= size <= max_bytes:
        raise ValueError("upload size is outside the allowed range")
    return name, content_type, size

def parse_bearer_token(
    header: str, min_length: int = 16, max_length: int = 512
) -> str:
    if not isinstance(header, str):
        raise TypeError("authorization header must be a string")
    if any(
        isinstance(value, bool) or not isinstance(value, int)
        for value in (min_length, max_length)
    ):
        raise TypeError("token length bounds must be integers")
    if min_length < 1 or max_length < min_length:
        raise ValueError("invalid token length bounds")
    if not header.startswith("Bearer "):
        raise ValueError("authorization scheme must be Bearer")

    token = header[7:]
    if not min_length <= len(token) <= max_length:
        raise ValueError("bearer token length is outside the allowed range")
    if any(not 33 <= ord(char) <= 126 for char in token):
        raise ValueError("bearer token must contain visible ASCII without spaces")
    return token

import hashlib
import hmac
import re


def token_digest_matches(presented: str, expected_sha256_hex: str) -> bool:
    if not isinstance(presented, str):
        raise TypeError("presented token must be a string")
    if not isinstance(expected_sha256_hex, str) or re.fullmatch(
        r"[0-9a-f]{64}", expected_sha256_hex
    ) is None:
        raise ValueError("expected digest must be 64 lowercase hexadecimal characters")

    actual = hashlib.sha256(presented.encode("utf-8")).digest()
    expected = bytes.fromhex(expected_sha256_hex)
    return hmac.compare_digest(actual, expected)

from pathlib import PurePosixPath


def validate_archive_member_names(names: list[str]) -> list[str]:
    if not isinstance(names, list):
        raise TypeError("names must be a list")

    result: list[str] = []
    for name in names:
        if not isinstance(name, str) or not name:
            raise ValueError("archive member names must be non-empty strings")
        if "\\" in name or any(ord(c) < 32 or ord(c) == 127 for c in name):
            raise ValueError("archive member name contains a forbidden character")
        path = PurePosixPath(name)
        if path.is_absolute():
            raise ValueError("archive member name must be relative")
        raw_parts = name.split("/")
        if any(part in {"", ".", ".."} for part in raw_parts):
            raise ValueError("archive member name has an unsafe path component")
        if ":" in raw_parts[0]:
            raise ValueError("archive member name contains a drive-like prefix")
        result.append(name)
    return result

def require_bounded_text_list(
    value: object,
    max_items: int,
    max_chars_each: int,
    max_total_chars: int,
) -> list[str]:
    limits = (max_items, max_chars_each, max_total_chars)
    if any(isinstance(limit, bool) or not isinstance(limit, int) for limit in limits):
        raise TypeError("limits must be integers")
    if any(limit < 0 for limit in limits):
        raise ValueError("limits must be non-negative")
    if not isinstance(value, list):
        raise TypeError("value must be a list")
    if len(value) > max_items:
        raise ValueError("too many items")

    result: list[str] = []
    total = 0
    for item in value:
        if not isinstance(item, str):
            raise TypeError("every item must be a string")
        cleaned = item.strip()
        if not cleaned:
            raise ValueError("items must not be blank")
        if len(cleaned) > max_chars_each:
            raise ValueError("an item exceeds the per-item limit")
        total += len(cleaned)
        if total > max_total_chars:
            raise ValueError("items exceed the total character limit")
        result.append(cleaned)
    return result

def require_single_line_header_value(
    value: object, max_length: int = 1024
) -> str:
    if isinstance(max_length, bool) or not isinstance(max_length, int) or max_length < 1:
        raise ValueError("max_length must be a positive integer")
    if not isinstance(value, str):
        raise TypeError("header value must be a string")
    if not value or len(value) > max_length:
        raise ValueError("header value length is outside the allowed range")
    if any(ord(char) < 32 or ord(char) == 127 for char in value):
        raise ValueError("header value contains a control character")
