from urllib.parse import urlsplit


def require_allowed_origin(value: str, allowed_origins: set[str]) -> str:
    if not isinstance(value, str) or value != value.strip() or not value:
        raise ValueError("origin must be non-blank canonical text")
    if not isinstance(allowed_origins, set) or any(
        not isinstance(item, str) or not item for item in allowed_origins
    ):
        raise TypeError("allowed_origins must be a set of strings")

    parts = urlsplit(value)
    if parts.scheme not in {"http", "https"} or not parts.hostname:
        raise ValueError("origin must use http or https")
    if parts.username is not None or parts.password is not None:
        raise ValueError("origin must not contain credentials")
    if parts.path or parts.query or parts.fragment:
        raise ValueError("origin must not contain a path, query, or fragment")
    try:
        port = parts.port
    except ValueError as exc:
        raise ValueError("origin contains an invalid port") from exc

    host = parts.hostname.lower()
    if any(ord(char) > 127 for char in host):
        raise ValueError("origin host must be ASCII")
    display_host = f"[{host}]" if ":" in host else host
    canonical = f"{parts.scheme.lower()}://{display_host}"
    if port is not None:
        canonical += f":{port}"
    if canonical not in allowed_origins:
        raise PermissionError("origin is not allowed")
    return canonical

function parseContentLength(value: unknown, maximum: number): number {
  if (!Number.isSafeInteger(maximum) || maximum < 0) {
    throw new RangeError("maximum must be a non-negative safe integer");
  }
  if (typeof value !== "string" || !/^(0|[1-9]\d*)$/.test(value)) {
    throw new TypeError("content length must be canonical decimal text");
  }
  const parsed = Number(value);
  if (!Number.isSafeInteger(parsed) || parsed > maximum) {
    throw new RangeError("content length is outside the allowed range");
  }
  return parsed;
}

type ProfilePatch = { displayName?: string; timezone?: string };

function parseProfilePatch(value: unknown): ProfilePatch {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    throw new TypeError("profile patch must be an object");
  }
  const prototype = Object.getPrototypeOf(value);
  if (prototype !== Object.prototype && prototype !== null) {
    throw new TypeError("profile patch must be a plain object");
  }

  const source = value as Record<string, unknown>;
  const allowed = new Set(["displayName", "timezone"]);
  for (const key in source) {
    if (!Object.hasOwn(source, key)) throw new Error(`inherited field is not allowed: ${key}`);
  }
  for (const key of Object.keys(source)) {
    if (!allowed.has(key)) throw new Error(`unexpected field: ${key}`);
  }

  const result: ProfilePatch = {};
  const read = (key: "displayName" | "timezone", maximum: number): string | undefined => {
    if (!Object.hasOwn(source, key)) return undefined;
    const item = source[key];
    if (typeof item !== "string" || !item.trim() || item !== item.trim()) {
      throw new TypeError(`${key} must be a trimmed non-blank string`);
    }
    if (item.length > maximum) throw new RangeError(`${key} is too long`);
    return item;
  };

  const displayName = read("displayName", 80);
  const timezone = read("timezone", 64);
  if (displayName !== undefined) result.displayName = displayName;
  if (timezone !== undefined) result.timezone = timezone;
  return result;
}

function requireTenantAccess(
  actor: { tenantId: string; system: boolean },
  resource: { tenantId: string },
): void {
  for (const [field, value] of [
    ["actor.tenantId", actor.tenantId],
    ["resource.tenantId", resource.tenantId],
  ] as const) {
    if (typeof value !== "string" || value !== value.trim() || value.length === 0) {
      throw new TypeError(`${field} must be a trimmed non-blank string`);
    }
  }
  if (typeof actor.system !== "boolean") throw new TypeError("actor.system must be boolean");
  if (!actor.system && actor.tenantId !== resource.tenantId) {
    throw new Error("actor is not authorized for this tenant resource");
  }
}

function validateWebhookTimestamp(
  value: unknown,
  nowSeconds: number,
  maxAgeSeconds = 300,
  maxFutureSkewSeconds = 30,
): number {
  for (const [name, item] of [
    ["nowSeconds", nowSeconds],
    ["maxAgeSeconds", maxAgeSeconds],
    ["maxFutureSkewSeconds", maxFutureSkewSeconds],
  ] as const) {
    if (!Number.isSafeInteger(item) || item < 0) {
      throw new RangeError(`${name} must be a non-negative safe integer`);
    }
  }
  if (typeof value !== "number" || !Number.isSafeInteger(value) || value < 0) {
    throw new TypeError("timestamp must be a non-negative integer number");
  }
  if (value < nowSeconds - maxAgeSeconds) throw new Error("timestamp is too old");
  if (value > nowSeconds + maxFutureSkewSeconds) throw new Error("timestamp is too far in the future");
  return value;
}

function parseBoundedMetadata(
  value: unknown,
  maxEntries = 20,
  maxValueLength = 200,
): Map<string, string> {
  if (!Number.isSafeInteger(maxEntries) || maxEntries < 0) throw new RangeError("invalid maxEntries");
  if (!Number.isSafeInteger(maxValueLength) || maxValueLength < 0) throw new RangeError("invalid maxValueLength");
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    throw new TypeError("metadata must be an object");
  }
  const prototype = Object.getPrototypeOf(value);
  if (prototype !== Object.prototype && prototype !== null) {
    throw new TypeError("metadata must be a plain object");
  }

  const entries = Object.entries(value as Record<string, unknown>);
  if (entries.length > maxEntries) throw new RangeError("too many metadata entries");
  const forbidden = new Set(["__proto__", "prototype", "constructor"]);
  const result = new Map<string, string>();
  for (const [key, item] of entries) {
    if (forbidden.has(key) || !/^[a-z0-9_]{1,40}$/.test(key)) {
      throw new Error(`invalid metadata key: ${key}`);
    }
    if (typeof item !== "string" || item.length > maxValueLength) {
      throw new TypeError(`invalid metadata value for ${key}`);
    }
    result.set(key, item);
  }
  return result;
}

function requireRequestedFields(
  value: unknown,
  allowed: readonly string[],
  maximum = 10,
): string[] {
  if (!Number.isSafeInteger(maximum) || maximum < 0) throw new RangeError("invalid maximum");
  const allowedSet = new Set<string>();
  for (const field of allowed) {
    if (typeof field !== "string" || !field.trim() || field !== field.trim()) {
      throw new TypeError("allowed fields must be trimmed non-blank strings");
    }
    if (allowedSet.has(field)) throw new Error(`duplicate allowed field: ${field}`);
    allowedSet.add(field);
  }
  if (!Array.isArray(value) || value.length > maximum) throw new TypeError("invalid requested field list");

  const seen = new Set<string>();
  const result: string[] = [];
  for (const field of value) {
    if (typeof field !== "string" || !allowedSet.has(field)) throw new Error("unknown requested field");
    if (seen.has(field)) throw new Error(`duplicate requested field: ${field}`);
    seen.add(field);
    result.push(field);
  }
  return result;
}

type Actor = { id: string };
type DocumentMetadata = { id: string };
type PrivateDocument = { id: string; body: string };
type Repository = { get(id: string): Promise<PrivateDocument> };

declare function canRead(actor: Actor, metadata: DocumentMetadata): boolean;

async function loadPrivateDocument(
  actor: Actor,
  metadata: DocumentMetadata,
  repository: Repository,
): Promise<PrivateDocument> {
  if (!canRead(actor, metadata)) throw new Error("not authorized");
  return repository.get(metadata.id);
}

