function requireCsrfTokenPair(cookieToken: unknown, headerToken: unknown): void {
  const read = (name: string, value: unknown): string => {
    if (typeof value !== "string" || value.length < 16 || value.length > 256) {
      throw new TypeError(`${name} has an invalid length`);
    }
    for (const character of value) {
      const code = character.charCodeAt(0);
      if (code < 33 || code > 126) throw new TypeError(`${name} contains an invalid character`);
    }
    return value;
  };
  const cookie = read("cookie token", cookieToken);
  const header = read("header token", headerToken);
  if (cookie !== header) throw new Error("CSRF token mismatch");
}

function decodeBase64UrlPayload(value, maxBytes) {
  if (!Number.isSafeInteger(maxBytes) || maxBytes < 0) throw new RangeError("invalid maxBytes");
  if (typeof value !== "string" || !/^[A-Za-z0-9_-]*$/.test(value)) {
    throw new TypeError("payload must be unpadded base64url text");
  }
  const decoded = Buffer.from(value, "base64url");
  if (decoded.length > maxBytes) throw new RangeError("decoded payload is too large");
  if (decoded.toString("base64url") !== value) throw new Error("payload is not canonical base64url");
  return decoded;
}

function buildSessionCookie(name, value, secure = true) {
  if (typeof name !== "string" || !/^[A-Za-z0-9!#$%&'*+.^_`|~-]+$/.test(name)) {
    throw new TypeError("invalid cookie name");
  }
  if (typeof value !== "string" || !/^[\x21\x23-\x2B\x2D-\x3A\x3C-\x5B\x5D-\x7E]+$/.test(value)) {
    throw new TypeError("invalid cookie value");
  }
  if (typeof secure !== "boolean") throw new TypeError("secure must be boolean");
  const attributes = [`${name}=${value}`, "Path=/", "HttpOnly", "SameSite=Strict"];
  if (secure) attributes.push("Secure");
  return attributes.join("; ");
}

function redactLogObject(record, sensitiveNames) {
  if (record === null || typeof record !== "object" || Array.isArray(record)) {
    throw new TypeError("record must be an object");
  }
  const prototype = Object.getPrototypeOf(record);
  if (prototype !== Object.prototype && prototype !== null) throw new TypeError("record must be plain");
  if (!Array.isArray(sensitiveNames)) throw new TypeError("sensitiveNames must be an array");
  const sensitive = new Set(sensitiveNames.map((name) => {
    if (typeof name !== "string" || !name.trim()) throw new TypeError("invalid sensitive name");
    return name.toLowerCase();
  }));
  const result = Object.create(null);
  for (const [key, value] of Object.entries(record)) {
    result[key] = sensitive.has(key.toLowerCase()) ? "[REDACTED]" : value;
  }
  return result;
}

function requireWorkspacePermission(actor, workspace, permission) {
  if (!actor || typeof actor.id !== "string" || !actor.id.trim()) throw new TypeError("invalid actor");
  if (!workspace || typeof workspace.id !== "string" || !workspace.id.trim()) throw new TypeError("invalid workspace");
  if (!(workspace.members instanceof Map)) throw new TypeError("workspace.members must be a Map");
  if (typeof permission !== "string" || !permission.trim()) throw new TypeError("invalid permission");
  const permissions = workspace.members.get(actor.id);
  if (!(permissions instanceof Set) || !permissions.has(permission)) {
    throw new Error("actor is not authorized for this workspace action");
  }
}

function parseUploadChunkDescriptor(value, maxChunks, maxChunkBytes) {
  if (!Number.isSafeInteger(maxChunks) || maxChunks < 1) throw new RangeError("maxChunks is invalid");
  if (!Number.isSafeInteger(maxChunkBytes) || maxChunkBytes < 0) throw new RangeError("maxChunkBytes is invalid");
  if (value === null || typeof value !== "object" || Array.isArray(value)) throw new TypeError("descriptor must be an object");
  const prototype = Object.getPrototypeOf(value);
  if (prototype !== Object.prototype && prototype !== null) throw new TypeError("descriptor must be plain");
  const keys = Object.keys(value).sort();
  if (keys.join(",") !== "index,size,total") throw new Error("descriptor fields are invalid");
  const { index, total, size } = value;
  if (![index, total, size].every(Number.isSafeInteger)) throw new TypeError("descriptor values must be safe integers");
  if (total < 1 || total > maxChunks || index < 0 || index >= total || size < 0 || size > maxChunkBytes) {
    throw new RangeError("descriptor values are outside the allowed range");
  }
  return { index, total, size };
}

function literalSearchRegex(text, flags = "u") {
  if (typeof text !== "string" || typeof flags !== "string") throw new TypeError("text and flags must be strings");
  if (!/^[dgimsuvy]*$/.test(flags) || new Set(flags).size !== flags.length) {
    throw new TypeError("invalid or duplicate regular-expression flags");
  }
  const escaped = text.replace(/[\\^$.*+?()[\]{}|/]/g, "\\$&");
  return new RegExp(escaped, flags);
}

