function ConvertFrom-BoundedJsonObject {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string] $Text,

        [ValidateRange(1, 1048576)]
        [int] $MaxCharacters = 16384
    )

    if ($Text.Length -gt $MaxCharacters) {
        throw 'JSON text exceeds the allowed size.'
    }

    try {
        $Value = $Text | ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        throw [System.ArgumentException]::new('Invalid JSON text.', $_.Exception)
    }

    if ($null -eq $Value -or $Value -is [System.Array] -or $Value -isnot [pscustomobject]) {
        throw 'JSON root must be an object.'
    }
    return $Value
}

function Assert-AuthorizedOwner {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string] $ActorId,

        [Parameter(Mandatory)]
        [string] $OwnerId,

        [switch] $IsAdministrator
    )

    if ([string]::IsNullOrWhiteSpace($ActorId) -or $ActorId -ne $ActorId.Trim()) {
        throw 'ActorId must be trimmed non-blank text.'
    }
    if ([string]::IsNullOrWhiteSpace($OwnerId) -or $OwnerId -ne $OwnerId.Trim()) {
        throw 'OwnerId must be trimmed non-blank text.'
    }
    if ($ActorId -ne $OwnerId -and -not $IsAdministrator.IsPresent) {
        throw [System.UnauthorizedAccessException]::new('Actor is not authorized for this resource.')
    }
}

function ConvertTo-SingleLineHeaderValue {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string] $Value,

        [ValidateRange(1, 8192)]
        [int] $MaxLength = 1024
    )

    if ($Value.Length -eq 0 -or $Value.Length -gt $MaxLength) {
        throw 'Header value length is outside the allowed range.'
    }
    foreach ($Character in $Value.ToCharArray()) {
        $Code = [int] $Character
        if ($Code -lt 32 -or $Code -eq 127) {
            throw 'Header value contains a control character.'
        }
    }
    return $Value
}

function ConvertTo-UploadMetadata {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $Name,
        [Parameter(Mandatory)] [string] $ContentType,
        [Parameter(Mandatory)] [long] $Length,
        [Parameter(Mandatory)] [string[]] $AllowedContentType,
        [Parameter(Mandatory)] [long] $MaxBytes
    )

    if ([string]::IsNullOrWhiteSpace($Name) -or $Name -ne $Name.Trim() -or $Name.Length -gt 128) {
        throw 'Invalid upload name.'
    }
    if ($Name -in @('.', '..') -or $Name.Contains('/') -or $Name.Contains('\')) {
        throw 'Upload name must not contain path syntax.'
    }
    if ($Name.ToCharArray() | Where-Object { [int] $_ -lt 32 -or [int] $_ -eq 127 }) {
        throw 'Upload name contains a control character.'
    }
    if ($MaxBytes -lt 0) {
        throw 'MaxBytes must be non-negative.'
    }
    if ($ContentType -ne $ContentType.Trim().ToLowerInvariant()) {
        throw 'ContentType must be canonical lowercase text.'
    }
    foreach ($Allowed in $AllowedContentType) {
        if ([string]::IsNullOrWhiteSpace($Allowed) -or $Allowed -ne $Allowed.Trim().ToLowerInvariant()) {
            throw 'AllowedContentType must contain canonical lowercase values.'
        }
    }
    if ($ContentType -notin $AllowedContentType) {
        throw 'Content type is not allowed.'
    }
    if ($Length -lt 0 -or $Length -gt $MaxBytes) {
        throw 'Upload length is outside the allowed range.'
    }

    [pscustomobject] @{
        Name        = $Name
        ContentType = $ContentType
        Length      = $Length
    }
}

function Test-AllowedCallbackUri {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] [string] $Value,
        [Parameter(Mandatory)] [string[]] $AllowedHost
    )

    foreach ($HostName in $AllowedHost) {
        if ([string]::IsNullOrWhiteSpace($HostName) -or $HostName -ne $HostName.Trim()) {
            throw 'AllowedHost must contain trimmed non-blank host names.'
        }
    }

    $Uri = $null
    if (-not [uri]::TryCreate($Value, [System.UriKind]::Absolute, [ref] $Uri)) {
        return $false
    }
    if ($Uri.Scheme -ne 'https' -or -not $Uri.IsDefaultPort -or -not [string]::IsNullOrEmpty($Uri.UserInfo)) {
        return $false
    }
    if ($Uri.AbsolutePath -ne '/callback' -or -not [string]::IsNullOrEmpty($Uri.Query) -or -not [string]::IsNullOrEmpty($Uri.Fragment)) {
        return $false
    }
    return $Uri.Host -in $AllowedHost
}
